// getAttribute nümunəsi
const image = document.querySelector('#myImage');
const srcValue = image.getAttribute('src');
console.log('Şəkil yolu:', srcValue); // Şəkil yolunu konsola yazdırır

const altValue = image.getAttribute('alt');
console.log('Alternativ mətn:', altValue); // Alternativ mətni konsola yazdırır

// setAttribute nümunəsi
const image = document.querySelector('#myImage');
image.setAttribute('src', 'new-image.jpg'); // Şəkil yolunu dəyişdirir
image.setAttribute('alt', 'Yeni şəkil'); // Alternativ mətni dəyişdirir

// Hadisə ilə atribut dəyişdirmə nümunəsi
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  button.setAttribute('disabled', 'true'); // Düyməni deaktiv edir
  console.log('Düymə deaktiv edildi');
});

// Səhvə yol açan nümunə
const element = document.querySelector('#nonExistent');
const value = element.getAttribute('id'); // TypeError: Cannot read property 'getAttribute' of null

// Düzgün yol
const safeElement = document.querySelector('#nonExistent');
if (safeElement) {
  const value = safeElement.getAttribute('id');
  console.log('ID:', value);
} else {
  console.log('Element tapılmadı');
}

// getAttribute example
const image = document.querySelector('#myImage');
const srcValue = image.getAttribute('src');
console.log('Image source:', srcValue); // Logs the image source

const altValue = image.getAttribute('alt');
console.log('Alt text:', altValue); // Logs the alt text

// setAttribute example
const image = document.querySelector('#myImage');
image.setAttribute('src', 'new-image.jpg'); // Changes the image source
image.setAttribute('alt', 'New picture'); // Changes the alt text

// Event-driven attribute change example
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  button.setAttribute('disabled', 'true'); // Disables the button
  console.log('Button disabled');
});

// Error-prone example
const element = document.querySelector('#nonExistent');
const value = element.getAttribute('id'); // TypeError: Cannot read property 'getAttribute' of null

// Correct approach
const safeElement = document.querySelector('#nonExistent');
if (safeElement) {
  const value = safeElement.getAttribute('id');
  console.log('ID:', value);
} else {
  console.log('Element not found');
}

// Пример getAttribute
const image = document.querySelector('#myImage');
const srcValue = image.getAttribute('src');
console.log('Источник изображения:', srcValue); // Выводит источник изображения

const altValue = image.getAttribute('alt');
console.log('Альтернативный текст:', altValue); // Выводит альтернативный текст

// Пример setAttribute
const image = document.querySelector('#myImage');
image.setAttribute('src', 'new-image.jpg'); // Изменяет источник изображения
image.setAttribute('alt', 'Новая картинка'); // Изменяет альтернативный текст

// Пример изменения атрибута с событием
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  button.setAttribute('disabled', 'true'); // Отключает кнопку
  console.log('Кнопка отключена');
});

// Пример с ошибкой
const element = document.querySelector('#nonExistent');
const value = element.getAttribute('id'); // TypeError: Cannot read property 'getAttribute' of null

// Правильный подход
const safeElement = document.querySelector('#nonExistent');
if (safeElement) {
  const value = safeElement.getAttribute('id');
  console.log('ID:', value);
} else {
  console.log('Элемент не найден');
}
